@app.route('/')
def home():
    return render_template_string(HOME_TEMPLATE, title="Home")


@app.route('/register', methods=['GET', 'POST'])
def register():
    if session.get('username'):
        return redirect(url_for('dashboard'))

    if request.method == 'POST':
        username = request.form.get('username', '').strip()
        password = request.form.get('password', '')
        confirm_password = request.form.get('confirm_password', '')

        if not username or not password:
            flash('Username and password are required.', 'error')
            return render_template_string(REGISTER_TEMPLATE, title="Register")

        if len(username) < 3:
            flash('Username must be at least 3 characters long.', 'error')
            return render_template_string(REGISTER_TEMPLATE, title="Register")

        if len(password) < 6:
            flash('Password must be at least 6 characters long.', 'error')
            return render_template_string(REGISTER_TEMPLATE, title="Register")

        if password != confirm_password:
            flash('Passwords do not match.', 'error')
            return render_template_string(REGISTER_TEMPLATE, title="Register")

        success, message = register_user(username, password)
        if success:
            flash(message + ' Please log in.', 'success')
            return redirect(url_for('login'))
        else:
            flash(message, 'error')

    return render_template_string(REGISTER_TEMPLATE, title="Register")


@app.route('/login', methods=['GET', 'POST'])
def login():
    if session.get('username'):
        return redirect(url_for('dashboard'))

    if request.method == 'POST':
        username = request.form.get('username', '').strip()
        password = request.form.get('password', '')
        remember = request.form.get('remember') == '1'

        if not username or not password:
            flash('Username and password are required.', 'error')
            return render_template_string(LOGIN_TEMPLATE, title="Login")

        if authenticate_user(username, password):
            # Clean up expired sessions first
            cleanup_expired_sessions()

            # Create a new session
            session_id = create_session(username)

            # Store in Flask session
            session['session_id'] = session_id
            session['username'] = username
            session.permanent = True

            # If "remember me", extend session lifetime
            if remember:
                sessions_db[session_id]['last_active'] = time.time()
                # We'll use a flag to track extended sessions
                sessions_db[session_id]['remember'] = True

            flash('Logged in successfully!', 'success')

            # Redirect to next page if specified
            next_page = request.args.get('next')
            if next_page:
                return redirect(next_page)
            return redirect(url_for('dashboard'))
        else:
            flash('Invalid username or password.', 'error')

    return render_template_string(LOGIN_TEMPLATE, title="Login")


@app.route('/logout', methods=['GET', 'POST'])
def logout():
    session_id = session.get('session_id')
    if session_id:
        destroy_session(session_id)
    session.pop('session_id', None)
    session.pop('username', None)
    session.clear()
    flash('You have been logged out.', 'info')
    return redirect(url_for('home'))


